import{_ as l,o as a,c as n,ak as e,as as o}from"./chunks/framework.DLt_otXO.js";const y=JSON.parse('{"title":"Flex布局","description":"","frontmatter":{"title":"Flex布局","date":"2021-11-30T11:29:40.000Z","permalink":"/pages/ecee9f/","categories":["CSS和LESS","CSS和CSS3"],"tags":[null]},"headers":[],"relativePath":"CSS和LESS/CSS和CSS3/Flex布局.md","filePath":"CSS和LESS/CSS和CSS3/Flex布局.md","lastUpdated":1777258973000}'),t={name:"CSS和LESS/CSS和CSS3/Flex布局.md"};function r(p,s,c,i,d,E){return a(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="flex布局" tabindex="-1">Flex布局 <a class="header-anchor" href="#flex布局" aria-label="Permalink to “Flex布局”">​</a></h1><h2 id="_1-flex布局是什么" tabindex="-1">1. Flex布局是什么 <a class="header-anchor" href="#_1-flex布局是什么" aria-label="Permalink to “1. Flex布局是什么”">​</a></h2><p><strong>Flex</strong>是 <strong>Flexible Box</strong>的缩写，意为<strong>弹性布局</strong>，用来为盒装模型提供最大的灵活性。任何一个容器都可以指定为<strong>Flex</strong>布局。</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  display</span><span style="color:#E1E4E8;">:</span><span style="color:#79B8FF;">flex</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><p>行内元素也可以使用<strong>Flex</strong>布局</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  display</span><span style="color:#E1E4E8;">:</span><span style="color:#79B8FF;">inline-flex</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><h2 id="_2-基本概念" tabindex="-1">2. 基本概念 <a class="header-anchor" href="#_2-基本概念" aria-label="Permalink to “2. 基本概念”">​</a></h2><p>采用Flex布局的元素，称为Flex容器，简称 <strong>容器</strong>。它的所有子元素自动成为容器成员，称为Flex项目，简称 <strong>项目</strong></p><img src="`+o+`"><p>容器默认存在两根轴： 水平的交<strong>主轴</strong>（main axis）和垂直的<strong>交叉轴</strong>（cross axis），主轴的开始位置（与边框的交叉点）叫做<strong>main start</strong>，结束位置叫做<strong>main end</strong>。交叉轴的开始位置叫做<strong>cross start</strong>，结束位置叫做<strong>cross end</strong>。</p><p>项目默认沿着主轴排列。单个项目占据的主轴空间叫做<strong>main size</strong>，占据的交叉轴的空间叫做<strong>cross size</strong></p><h2 id="_3-容器属性" tabindex="-1">3. 容器属性 <a class="header-anchor" href="#_3-容器属性" aria-label="Permalink to “3. 容器属性”">​</a></h2><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#85E89D;">flex-direction</span></span>
<span class="line"><span style="color:#85E89D;">flex-wrap</span></span>
<span class="line"><span style="color:#85E89D;">flex-flow</span></span>
<span class="line"><span style="color:#85E89D;">jusitify-content</span></span>
<span class="line"><span style="color:#85E89D;">align-items</span></span>
<span class="line"><span style="color:#85E89D;">aligin-content</span></span></code></pre></div><h3 id="_3-1-flex-direction" tabindex="-1">3.1 flex-direction <a class="header-anchor" href="#_3-1-flex-direction" aria-label="Permalink to “3.1 flex-direction”">​</a></h3><p><code>flex-direction</code>属性决定<strong>主轴的方向</strong>（既项目的排列方向）</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  flex-direction</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">row</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">row-reverse</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">column</span><span style="color:#E1E4E8;"> | column-revberse;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><ul><li><ol><li>row (默认值) ：主轴在<strong>水平方向</strong>，起点在<strong>左端</strong></li></ol></li><li><ol start="2"><li>row-reverse ： 主轴在<strong>水平方向</strong>，起点在<strong>右端</strong></li></ol></li><li><ol start="3"><li>column ：主轴在<strong>垂直方向</strong>，起点在<strong>顶端</strong></li></ol></li><li><ol start="4"><li>column-revberse ： 主轴在<strong>垂直方向</strong>，起点在<strong>底端</strong></li></ol></li></ul><h3 id="_3-2-flex-wrap" tabindex="-1">3.2 flex-wrap <a class="header-anchor" href="#_3-2-flex-wrap" aria-label="Permalink to “3.2 flex-wrap”">​</a></h3><p>默认情况下，项目都排在一条线上（轴线）。<strong>flex-direction</strong>属性定义，如果一条轴线排不下，如何<strong>换行</strong></p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#85E89D;">flex-wrap</span><span style="color:#E1E4E8;"> : nowrap  | wrap | </span><span style="color:#85E89D;">wrap-reverse</span><span style="color:#E1E4E8;">;</span></span></code></pre></div><ul><li><ol><li>nowrap : 不换行（默认）</li></ol></li><li><ol start="2"><li>wrap : 换行（第一行在上方）</li></ol></li><li><ol start="3"><li>wrap-reverse ： 换行（第一行在下方）</li></ol></li><li></li></ul><h3 id="_3-3-flex-flow" tabindex="-1">3.3 flex-flow <a class="header-anchor" href="#_3-3-flex-flow" aria-label="Permalink to “3.3 flex-flow”">​</a></h3><p>flex-flow 属性是<code>flex-direction</code>和<code>flex-flex-wrap</code>的简写形式。默认值为 <code>row nowrap</code></p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  flex-flow</span><span style="color:#E1E4E8;"> : &lt;flex-direction&gt; || &lt;flex-wrap&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><h3 id="_3-4-jusitify-content" tabindex="-1">3.4 jusitify-content <a class="header-anchor" href="#_3-4-jusitify-content" aria-label="Permalink to “3.4 jusitify-content”">​</a></h3><p>该属性定义了<strong>项目</strong>在<strong>主轴</strong>上的<strong>对齐方式</strong></p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  justify-content</span><span style="color:#E1E4E8;"> : </span><span style="color:#79B8FF;">flex-start</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">flex-end</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">center</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">space-between</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">space-around</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><ul><li><ol><li>flex-start : (默认值)： 左对齐</li></ol></li><li><ol start="2"><li>flex-end : 右对齐</li></ol></li><li><ol start="3"><li>center : 居中</li></ol></li><li><ol start="4"><li>space-between : 两端对齐，项目之间的间隔都相等。</li></ol></li><li><ol start="5"><li>space-around: 每个项目两侧的间隔相等。所以，项目之间的间隔比项目与边框的间隔大一倍。</li></ol></li></ul><h3 id="_3-5-align-items" tabindex="-1">3.5 align-items <a class="header-anchor" href="#_3-5-align-items" aria-label="Permalink to “3.5 align-items”">​</a></h3><p>该属性定义了<strong>项目</strong>在<strong>交叉轴</strong>上的<strong>对齐方式</strong></p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  align-items</span><span style="color:#E1E4E8;"> : </span><span style="color:#79B8FF;">flex-start</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">flex-end</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">center</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">baseline</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">stretch</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><ul><li><ol><li>flex-start : 交叉轴的起点对齐</li></ol></li><li><ol start="2"><li>flex-end : 交叉轴的终点对齐</li></ol></li><li><ol start="3"><li>center : 交叉轴的中点对齐</li></ol></li><li><ol start="4"><li>baseline : 项目的第一行文字的基线对齐</li></ol></li><li><ol start="5"><li>strctch : (默认值)，如果项目没有设置高度，或者高度为auto，将占满整个容器的高度</li></ol></li></ul><h3 id="_3-6-align-content" tabindex="-1">3.6 align-content <a class="header-anchor" href="#_3-6-align-content" aria-label="Permalink to “3.6 align-content”">​</a></h3><p>与<code>align-content</code>属性一样，定义了<strong>项目</strong>在<strong>交叉轴</strong>上的<strong>对齐方式</strong>。但是<code>align-content</code>生效需要<strong>多行</strong>，单行不起作用。</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.box</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  align-content</span><span style="color:#E1E4E8;"> : </span><span style="color:#79B8FF;">flex-start</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">flex-end</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">center</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">space-between</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">space-around</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">stretch</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><ul><li><ol><li>flex-start : 与交叉轴的起点对齐</li></ol></li><li><ol start="2"><li>flex-end : 与交叉轴的终点对齐</li></ol></li><li><ol start="3"><li>center : 与交叉轴的中点对齐</li></ol></li><li><ol start="4"><li>space-between : 与交叉轴两端对齐，轴线之间的间隔平均分布</li></ol></li><li><ol start="5"><li>space-around : 没根轴线的两侧间隔相等。所以，轴线之间的间隔比轴线与边框的间隔大一倍</li></ol></li><li><ol start="6"><li>stretch：（默认值），轴线占满整个交叉轴</li></ol></li></ul><h2 id="_4-项目属性" tabindex="-1">4. 项目属性 <a class="header-anchor" href="#_4-项目属性" aria-label="Permalink to “4. 项目属性”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span>order</span></span>
<span class="line"><span>flex-grow</span></span>
<span class="line"><span>flex-shrink</span></span>
<span class="line"><span>lex-basis</span></span>
<span class="line"><span>flex</span></span>
<span class="line"><span>align-self</span></span></code></pre></div><h3 id="_4-1-order" tabindex="-1">4.1 order <a class="header-anchor" href="#_4-1-order" aria-label="Permalink to “4.1 order”">​</a></h3><p><code>order</code>属性定义了项目的<strong>顺序</strong>。数字越小，排列越靠前，默认为0</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  order</span><span style="color:#E1E4E8;"> : &lt;integer&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><h3 id="_4-2-flex-grow" tabindex="-1">4.2 flex-grow <a class="header-anchor" href="#_4-2-flex-grow" aria-label="Permalink to “4.2 flex-grow”">​</a></h3><p><code>flex-grow</code>属性定义了项目的<strong>放大比例</strong>。<strong>默认为0</strong>，既如果存在剩余空间，也不放大。</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  flex-grow</span><span style="color:#E1E4E8;"> : &lt;number&gt;  </span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><p>如果所有项目的<code>flex-grow</code>属性都为1，则它们将等分剩余的空间。如果一个项目的<code>flex-grow</code>为2，其它项目为1，则前者占据的空间是其它像的2倍。</p><h3 id="_4-3-flex-shrink" tabindex="-1">4.3 flex-shrink <a class="header-anchor" href="#_4-3-flex-shrink" aria-label="Permalink to “4.3 flex-shrink”">​</a></h3><p><code>flex-shrink</code>属性定义了项目的<strong>缩小比例</strong>，<strong>默认为1</strong>，既如果空间不足，该项目将缩小</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#79B8FF;">  flex-shrink</span><span style="color:#E1E4E8;">:&lt;number&gt;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><p>如果所有项目的<code>flex-shrink</code>属性都是1，当空间不足时，都将等比例缩小。如果一个项目的<code>flex-shrink</code>属性为0，其它项目为1，则空间不足时，前者不缩小。</p><h3 id="_4-4-flex-basis" tabindex="-1">4.4 flex-basis <a class="header-anchor" href="#_4-4-flex-basis" aria-label="Permalink to “4.4 flex-basis”">​</a></h3><p><code>flex-basis</code> 属性定义了再分配多余空间之前。项目占据的主轴空间（main size）。浏览器根据这个属性，计算主轴是否有多余空间。它的默认值为<code>auto</code>，既项目的未来大小。</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  flex-basis</span><span style="color:#E1E4E8;"> :&lt;length&gt; | </span><span style="color:#79B8FF;">auto</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><p>它可以跟<code>width</code>或<code>height</code>属性一样的值（比如350px），则项目将占据固定空间。</p><h3 id="_4-5-flex" tabindex="-1">4.5 flex <a class="header-anchor" href="#_4-5-flex" aria-label="Permalink to “4.5 flex”">​</a></h3><p>flex 属性是 <code>flex-grow</code>，<code>flex-shrink</code>和<code>flex-basis</code>的简写。默认值为 <code>0 1 auto</code>。后两个属性可选</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  flex</span><span style="color:#E1E4E8;"> : </span><span style="color:#79B8FF;">none</span><span style="color:#E1E4E8;"> | [&lt;</span><span style="color:#9ECBFF;">&#39;flex-grow&#39;</span><span style="color:#E1E4E8;">&gt; &lt;</span><span style="color:#9ECBFF;">&#39;flex-shrink&#39;</span><span style="color:#E1E4E8;">&gt; ? || &lt;</span><span style="color:#9ECBFF;">&#39;flex-basis&#39;</span><span style="color:#E1E4E8;">&gt;]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><p>该属性有两个快捷值 ： auto （1 1 auto）和none （0 0 auto）。建议优先使用这个属性，而不是单独写三个分离的属性，因为浏览器会推算相关值。</p><h3 id="_4-6-align-self" tabindex="-1">4.6 align-self <a class="header-anchor" href="#_4-6-align-self" aria-label="Permalink to “4.6 align-self”">​</a></h3><p><code>align-self</code>设置单个项目的交叉轴对齐方式。值跟<code>align-items</code>属性值一样，可覆盖<code>align-items</code>属性。默认值为<code>auto</code>，表示继承父元素的<code>align-items</code>属性。</p><p>与<code>align-items</code>的区别就是： <code>align-items</code>设置所有项目的交叉轴对齐方式。<code>align-self</code>设置一个项目的交叉轴对齐方式，用来对<code>align-items</code>的值覆盖。</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#B392F0;">.item</span><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#79B8FF;">  align-self</span><span style="color:#E1E4E8;"> : </span><span style="color:#79B8FF;">auto</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">flex-start</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">flex-end</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">center</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">baseline</span><span style="color:#E1E4E8;"> | </span><span style="color:#79B8FF;">stretch</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre></div><ul><li><ol><li>flex-start : 交叉轴的起点对齐</li></ol></li><li><ol start="2"><li>flex-end : 交叉轴的终点对齐</li></ol></li><li><ol start="3"><li>center : 交叉轴的中点对齐</li></ol></li><li><ol start="4"><li>baseline : 项目的第一行文字的基线对齐</li></ol></li><li><ol start="5"><li>strctch : (默认值)，如果项目没有设置高度，或者高度为auto，将占满整个容器的高度</li></ol></li></ul>`,62)])])}const x=l(t,[["render",r]]);export{y as __pageData,x as default};
